&-operation {
  width: @size-6;
  width: var(--am-operation-icon-width, @size-6);
  height: @size-6;
  height: var(--am-operation-icon-height, @size-6);
  overflow: hidden;
  text-align: center;
  line-height: @size-6;
  line-height: var(--am-title-operation-lineHeight, @size-6);
  margin-left: @h-spacing-standard;
  margin-left: var(--am-title-operation-marginLeft, @h-spacing-standard);
  &-icon {
    font-size: @icon-size-xs;
    font-size: var(--am-title-operation-icon-size, @icon-size-xs);
    color: @color-text-weak;
    color: var(--am-title-operation-icon-color, @color-text-weak);
  }
}

// Default
.btn-default() {
    .button-variant(@btn-default-color; @btn-default-bg; @btn-default-border);

    &:hover
    //&:focus
    {
        .button-color(tint(@primary-color, 20%); white; tint(@primary-color, 20%));
    }
    &:active,
    &.active {
        .button-color(shade(@primary-color, 5%); white; shade(@primary-color, 5%));
    }
    .active-btn-color(@primary-color);
}

// Primary
.btn-primary() {
    .button-variant(@btn-primary-color; @btn-primary-bg; @primary-color);

    &:hover,
    //&:focus,
    &:active,
    &.active {
        color: @btn-primary-color;
    }
    .active-btn-color(@primary-color);
}

// Circle for Icon
.btn-circle(@btnClassName: ivu-btn) {
    border-radius: @btn-circle-size;

    &.@{btnClassName}-large{
        border-radius: @btn-circle-size-large;
    }

    &.@{btnClassName}-size{
        border-radius: @btn-circle-size-small;
    }

    &.@{btnClassName}-icon-only{
        .square(@btn-circle-size);
        .button-size(0; @font-size-base + 2; 50%);

        &.@{btnClassName}-large{
            .square(@btn-circle-size-large);
            .button-size(0; @btn-font-size-large + 2; 50%);
        }

        &.@{btnClassName}-small{
            .square(@btn-circle-size-small);
            .button-size(0; @font-size-base; 50%);
        }
    }
}

&-card {
  background: linear-gradient(180deg, var(--r-surface) 0%, var(--r-surface-2) 100%);
  border: 1px solid var(--r-line);
  padding: 18px 18px 16px;
  position: relative;
  overflow: hidden;
  transition: border-color .15s, box-shadow .15s;

  &:hover {
    border-color: var(--r-accent);
    box-shadow: 0 0 0 1px var(--r-accent-soft), 0 0 24px -8px var(--r-accent);
  }

  &::before {
    content: '';
    position: absolute; top: 0; right: 0;
    width: 16px; height: 16px;
    background: var(--r-bg);
    clip-path: polygon(100% 0, 0 0, 100% 100%);
    border-left: 1px solid var(--r-line);
    border-bottom: 1px solid var(--r-line);
  }

  &::after {
    content: '';
    position: absolute; inset: 0;
    background: repeating-linear-gradient(180deg, transparent 0 3px, var(--r-scanline-2) 3px 4px);
    pointer-events: none;
  }
}

&-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 8px;

  li {
    display: flex;
    align-items: center;
    gap: 10px;
    font-family: 'JetBrains Mono', monospace;
    font-size: 11px;
    letter-spacing: 0.08em;
    color: var(--r-text);
  }

  .pip {
    width: 10px;
    height: 10px;
    transform: rotate(45deg);
    flex: 0 0 10px;
    box-shadow: 0 0 8px currentColor;

    &.legendary { background: var(--r-gold);  color: var(--r-gold); }
    &.epic      { background: var(--r-epic);  color: var(--r-epic); }
    &.rare      { background: var(--r-rare);  color: var(--r-rare); }
    &.common    { background: var(--r-common); color: var(--r-common); box-shadow: none; }
  }
}

a {
	display: flex;
	align-items: center;
	text-decoration: none;
	margin-right: 20px;
	&>span {
		background-color: rgba(96,125,139,.05);
		line-height: 2.4;
		transition: all .15s;
		padding: 0 12px;
		margin-bottom: 15px;
		border-radius: 6px;
		position: relative;
		top: 0;
		color: #43576B;
		font-weight: 400;
		font-size: 16px;
		&:hover {
			top: -2px;
			background-color: #607d8b;
			color: #ffffff;
			transition: all .3s ease-in-out;
		}
		&>i {
			text-align: center;
			color: #F56C6C;
			font-size: 15px;
			font-weight: 500;
		}
