}

pre {
	font-size: .85em;
	line-height: 1.5em;
	display: flex;
	max-width: 1000px;
	position: relative;
	&:after {
		position: absolute;
		left: 20px;
		top: 30px;
		width: 12px;
		height: 12px;
		border-radius: 50%;
		background: #fc625d;
		-webkit-box-shadow: 20px 0 #fdbc40, 40px 0 #35cd4b;
		box-shadow: 20px 0 #fdbc40, 40px 0 #35cd4b;
		content: ' ';
	}
	code {
		flex: 1;
		text-align: left;
		width: fit-content;
		padding: 40px 20px 20px 20px;
		margin: 20px 0;
		white-space: pre;
		word-spacing: normal;
		word-break: normal;
		word-wrap: normal;
	}
