  &.@{prefix}-is-left::after {
    .bar-track-pseudo(1px, 100%, 0, 0);
  }

  &.@{prefix}-is-right::after {
    .bar-track-pseudo(1px, 100%, 0, auto, auto, 0);
  }

  &.@{prefix}-is-addable {
    margin-right: @tab-btn-width;
  }

  &.@{prefix}-tabs__nav--card {
    // border-bottom: 1px solid @tab-default-stroke;

    &::after {
      content: '';
      background-color: transparent;
    }
  }
}

&-text {
  position: relative;
  z-index: 2;
  flex-grow: 1;
  justify-content: space-around;
  align-self: center;
  &-title {
    font-weight: bold;
    font-size: @font-size-title;
    font-size: var(--am-coupon-title-size, @font-size-title);
    color: @color-text-title;
    color: var(--am-coupon-title-color, @color-text-title);
  }
  &-subtitle {
    margin-top: @v-spacing-standard;
    margin-top: var(--am-coupon-subTitle-marginTop, @v-spacing-standard);
    font-size: @font-size-content;
    font-size: var(--am-coupon-subtitle-size, @font-size-content);
    color: @color-text-subtitle;
    color: var(--am-coupon-subtitle-color, @color-text-subtitle);
  }
}

&-active {
  color: @color-text-primary;
  color: var(--am-notice-active-color, @color-text-primary);
  border: 0 none;
  background: none;
  &-bg {
    position: absolute;
    top: 0;
    left: 0;
    bottom: 0;
    right: 0;
    z-index: 1;
    border-color: tint(@color-fill-primary, 72%);
    border-color: var(--am-notice-active-borderColor, tint(@color-fill-primary, 72%));
    background-color: tint(@color-fill-primary, 80%);
    background-color: var(--am-notice-active-bgc, tint(@color-fill-primary, 80%));
  }
  &-scroll-left,
  &-scroll-right {
    background-color: tint(@color-fill-primary, 80%);
    background-color: var(--am-notice-active-bgc, tint(@color-fill-primary, 80%));
  }
}

&-btn {
  padding: 0 @h-spacing-large;
  padding: 0 var(--am-swipeAction-btn-paddingLR, @h-spacing-large);
  justify-content: center;
  align-items: center;
  display: flex;
  color: @color-text-base;
  color: var(--am-swipeAction-btn-color, @color-text-base);
  &-text {
    height: 1em;
    overflow: hidden;
    line-height: @line-height-base;
    line-height: var(--am-swipeAction-btn-lineHeight, @line-height-base);
  }

  &-delete {
    background-color: @color-fill-warning;
    background-color: var(--am-swipeAction-delete, @color-fill-warning);
  }

  &-edit {
    background-color: @color-fill-grey-base;
    background-color: var(--am-swipeAction-edit, @color-fill-grey-base);
  }
  &-other {
    background-color: @color-fill-primary;
    background-color: var(--am-swipeAction-other, @color-fill-primary);
  }
}

@primary-color          : #2d8cf0;
@info-color             : #2db7f5;
@success-color          : #19be6b;
@processing-color       : @primary-color;
@warning-color          : #ff9900;
@error-color            : #ed4014;
@normal-color           : #e6ebf1;
@link-color             : #2D8cF0;
@link-hover-color       : tint(@link-color, 20%);
@link-active-color      : shade(@link-color, 5%);
@selected-color         : fade(@primary-color, 90%);
@tooltip-color          : #fff;
@subsidiary-color       : #808695;
@rate-star-color        : #f5a623;
@white: #fff;
@black: #000;

// Base
@body-background        : #fff;
@component-background   : #fff;
@font-family            : "Helvetica Neue",Helvetica,"PingFang SC","Hiragino Sans GB","Microsoft YaHei","微软雅黑",Arial,sans-serif;
