    .shadow-around { box-shadow: @shadow-around; }
    .shadow-md-around { box-shadow: @shadow-md-around; }
    .shadow-lg-around { box-shadow: @shadow-lg-around; }
    .shadow-xl-around { box-shadow: @shadow-xl-around; }
    .shadow-2xl-around { box-shadow: @shadow-2xl-around; }
}

&&__stripe,
  &&__stripe-saas {
    .@{grid-prefix-cls}-body__row {
      // 支持所有行 hover 背景颜色
      &:not(.row__hover) {
        &:nth-child(2n) {
          background-color: var(--tiny-color-fill-8, #f4f6fb);
        }

        &.row__current {
          @apply bg-color-info-primary-subtler;
        }
      }

      &.row__selected {
        &:nth-child(2n) {
          @apply bg-color-info-primary-subtler;
        }

        &:nth-child(2n + 1) {
          background-color: var(--tiny-color-fill-8, #f4f6fb);
        }
      }
    }

    &.mark-insert {
      .@{grid-prefix-cls}-body__row.row__new {
        @apply bg-color-bg-2;
      }
    }
  }

&.col__treenode {
  .@{grid-prefix-cls}-cell {
    @apply flex;
    @apply items-center;
    // 解决树表的省略隐藏样式和AUI不兼容的问题，勿同步
    @apply w-full;

    .@{grid-prefix-cls}-tree__indent {
      @apply shrink-0;
    }

    .@{grid-prefix-cls}-tree-wrapper {
      @apply w-5;
      @apply h-5;
      @apply inline-flex;
      @apply justify-center;
      @apply items-center;
      @apply -translate-x-1;
      @apply shrink-0;
    }
  }

  &.col__ellipsis {
    .@{grid-prefix-cls}-cell {
      &__tooltip:has(.tiny-grid-tree__indent:nth-last-child(2):first-child),
      &__title:has(.tiny-grid-tree__indent:nth-last-child(2):first-child),
      &__ellipsis:has(.tiny-grid-tree__indent:nth-last-child(2):first-child) {
        @apply inline-block;
      }
    }
  }
}

&.is-display-only {
  .@{numeric-prefix-cls}-display-only {
    .@{numeric-prefix-cls}-display-only__content {
      @apply truncate;
    }
  }
  .@{numeric-prefix-cls}-display-only__unit {
    @apply ~'ml-[8px]';
  }
  .@{numeric-prefix-cls}__input {
    @apply border-none;
    @apply p-0;
    @apply leading-4;
    @apply h-4;

    &.@{input-prefix-cls}-small,
    &.@{input-prefix-cls}-medium,
    &.@{input-prefix-cls}-mini {
      @apply border-none;
      @apply p-0;
      @apply leading-4;
      @apply h-4;
    }
  }

  .@{numeric-prefix-cls}__input-inner,
  .@{numeric-prefix-cls}__unit,
  .@{numeric-prefix-cls}__decrease,
  .@{numeric-prefix-cls}__increase {
    @apply hidden;
  }
}

& &-body__hover-align-y-bar {
  --after-left-offset: 0;

  display: none;
  @apply ~'z-[9]';
  @apply absolute;
  @apply top-0;
  @apply left-0;

  &:before {
    @apply absolute;
    @apply content-[''];
    @apply block;
    @apply h-full;
    border-left-width: 1px;
    border-left-style: dashed;
    @apply border-color-border-focus;
  }

  &:after {
    @apply top-0;
    @apply right-0;
    @apply content-[''];
    @apply absolute;
    @apply block;
    @apply h-full;
    border-left-width: 1px;
    border-left-style: dashed;
    @apply border-color-border-focus;
    left: var(--after-left-offset);
  }
}

&.type__message {
  @apply text-center;

  .@{grid-modal-prefix-cls}__box {
    @apply inline-block;
    @apply ~'py-0.5 px-0';
    @apply mt-0;
    @apply w-auto;
    @apply shadow-lg;

    .@{grid-modal-prefix-cls}__body {
      &:after {
        @apply content-[''];
        @apply block;
        @apply clear-both;
        @apply h-0;
        @apply overflow-hidden;
        @apply invisible;
      }
    }

    .@{grid-modal-prefix-cls}__content {
      max-width: 800px;
      @apply float-left;
    }
  }

  .@{grid-modal-prefix-cls}__status-wrapper {
    @apply text-base;
    @apply ~'pr-2.5';
  }
}

p,
    ul:not(.vh-vhMusic ul, .vh-comment ul),
    ol:not(.vh-vhMusic ol, .vh-comment ol) {
      padding: 0.618rem 0;
      font-size: 0.9375rem;
      line-height: 1.6;

      li {
        color: var(--vh-font-66);
        font-size: 0.875rem;
        line-height: 1.6;
      }

      // 其下面的 a 标签样式
      a {
        color: var(--vh-font-56);
        box-shadow: inset 0 -.12rem var(--vh-main-color);
        transition: box-shadow .2s ease-in-out, color .2s ease-in-out;

        &:hover {
          box-shadow: inset 0 -1.5rem var(--vh-main-color-28);
        }
      }

      // 其下面的code标签样式
      code {
        background-color: var(--vh-font-16);
        padding: .125rem .375rem;
        font-size: 0.8125rem;
      }
    }
